function dealRecord(name: string): DealTrackingRecord {
  return {
    id: `deal-${name}`,
    dealName: name,
    counterparty: '',
    status: 'open',
    investorsContacted: 0,
    investorsResponded: 0,
    buyersContacted: 0,
    meetingsScheduled: 0,
    documentsShared: 0,
    offersReceived: 0,
    capitalTarget: null,
    capitalCommitted: null,
    closedAt: null,
    notes: '',
    source: 'verified_deal',
    sourceDetail: '',
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
}

